import SwiftUI
import Combine

class TradeViewModel: ObservableObject {
    @Published var stocks: [Stock] = []
    @Published var selectedStock: Stock?
    @Published var orderAmount: Double = 0
    @Published var errorMessage: String?

    private let apiService = APIService()

    func fetchStocks() {
        apiService.fetchStocks()
            .sink(receiveCompletion: { completion in
                if case .failure(let error) = completion {
                    self.errorMessage = error.localizedDescription
                }
            }, receiveValue: { stocks in
                self.stocks = stocks
            })
            .store(in: &cancellables)
    }

    func placeOrder() {
        guard let selectedStock = selectedStock, orderAmount > 0 else {
            return
        }

        apiService.placeOrder(stock: selectedStock, amount: orderAmount)
            .sink(receiveCompletion: { completion in
                if case .failure(let error) = completion {
                    self.errorMessage = error.localizedDescription
                }
            }, receiveValue: { _ in
                self.orderAmount = 0
            })
            .store(in: &cancellables)
    }
}

struct TradeView: View {
    @ObservedObject var viewModel = TradeViewModel()

    var body: some View {
        VStack {
            // Stock selection and order amount fields
            // ...

            Button("Place Order") {
                viewModel.placeOrder()
            }
            .padding()
        }
        .onAppear {
            viewModel.fetchStocks()
        }
    }
}